
-- 1) Remove duplicate awareness articles (keep one per unique content)
WITH ranked AS (
  SELECT id,
         row_number() OVER (PARTITION BY content ORDER BY created_at DESC, id) AS rn
  FROM public.articles
  WHERE category_id = '0654f763-a120-4133-85f2-8b68b7ecdcd7'
)
DELETE FROM public.articles a
USING ranked r
WHERE a.id = r.id AND r.rn > 1;

-- 2) Expand body content for the surviving awareness articles
UPDATE public.articles
SET content = content
  || E'\n\n— — —\n\n'
  || CASE
    WHEN content LIKE '%الذكاء الاصطناعي%' THEN
      E'## لماذا يهمّك الذكاء الاصطناعي اليوم؟\nالذكاء الاصطناعي لم يعد تقنية مستقبلية، بل واقع يومي يدخل في الهاتف، المتصفح، البريد، والتطبيقات الحكومية. من يفهمه يكسب وقتاً ومالاً، ومن يتجاهله يتأخّر.\n\n## مفاهيم يجب أن تعرفها\n- النموذج اللغوي الكبير (LLM): يفهم ويولّد النصوص.\n- التعلم الآلي (Machine Learning): يتعلم من البيانات بدل البرمجة المباشرة.\n- التعلم العميق (Deep Learning): شبكات عصبية متعددة الطبقات.\n- الـ Prompt Engineering: فن صياغة التعليمات للحصول على أفضل نتيجة.\n\n## استخدامات عملية فوراً\n1. تلخيص المستندات الطويلة في دقائق.\n2. الترجمة الفورية بمستوى احترافي.\n3. توليد صور ومحتوى تعليمي.\n4. مساعدتك في كتابة الإيميلات الرسمية والسير الذاتية.\n5. تحليل البيانات وعمل تقارير سريعة.\n\n## تحذيرات وأخلاقيات\n- لا تُدخل بيانات شخصية أو سرّية في الأدوات المفتوحة.\n- راجع المخرجات قبل النشر، فالنماذج تُخطئ أحياناً (Hallucination).\n- احترم حقوق الملكية الفكرية للصور والنصوص المُولَّدة.\n\n## مسار تعلّم مقترح للمبتدئ\nأسبوع 1: مقدمة عامة + تجربة ChatGPT/Gemini.\nأسبوع 2: أساسيات Prompting.\nأسبوع 3: تطبيقات عملية في عملك الحالي.\nأسبوع 4: مشروع شخصي صغير يوفّر عليك وقتاً.'
    WHEN content LIKE '%البرمجة%' THEN
      E'## لماذا البرمجة هي مهارة العصر؟\nالبرمجة تمنحك القدرة على بناء الأدوات بدل انتظارها. سوق العمل العالمي يفتح أبوابه لكل مبرمج، والعمل عن بُعد بات متاحاً من أي قرية في مصر.\n\n## من أين تبدأ؟\n- اختر لغة واحدة وأتقنها: Python للمبتدئ، JavaScript للويب.\n- تعلّم الأساسيات: المتغيّرات، الشروط، الحلقات، الدوال.\n- مارس يومياً ولو 30 دقيقة على منصّات مثل HackerRank وLeetCode.\n\n## مسارات احترافية\n1. تطوير الويب (Frontend / Backend / Full-Stack).\n2. تطبيقات الموبايل (Flutter / React Native).\n3. علم البيانات والذكاء الاصطناعي.\n4. الأمن السيبراني والاختراق الأخلاقي.\n5. تطوير الألعاب (Unity / Unreal).\n\n## أدوات لا غنى عنها\n- محرّر VS Code.\n- نظام إدارة الإصدارات Git ومنصة GitHub.\n- الطرفية (Terminal) والـ Shell.\n- أدوات الذكاء الاصطناعي المساعدة في الكتابة والتصحيح.\n\n## نصائح ذهبية\n- اقرأ الأكواد المفتوحة المصدر يومياً.\n- شارك في مشاريع GitHub لبناء سيرتك الذاتية.\n- لا تحفظ، بل افهم ثم طبّق.\n- ابنِ مشروعاً حقيقياً ينفع الناس.'
    WHEN content LIKE '%الأمن السيبراني%' OR content LIKE '%التصيّد%' THEN
      E'## الأمن السيبراني — درعك الرقمي\nكل ضغطة، كل تسجيل دخول، كل صورة على هاتفك — هدف محتمل للهجوم. حماية نفسك ليست رفاهية، بل واجب.\n\n## أشهر الهجمات اليومية\n- التصيّد الاحتيالي (Phishing): روابط تنتحل صفة بنوك أو شركات.\n- هندسة اجتماعية: انتحال شخصيات لانتزاع كلمات السر.\n- برمجيات الفدية (Ransomware): تشفّر ملفاتك مقابل دفع مبلغ.\n- اختراق الحسابات عبر كلمات السر الضعيفة المُسرّبة.\n\n## خطوات حماية فورية\n1. فعّل المصادقة الثنائية (2FA) على كل حساباتك.\n2. استخدم مدير كلمات سر موثوق (Bitwarden / 1Password).\n3. لا تُعِد استخدام نفس كلمة السر مطلقاً.\n4. حدّث نظامك وتطبيقاتك أسبوعياً.\n5. اعمل نسخة احتياطية على قرص خارجي أو سحابة موثوقة.\n6. تحقّق من رابط أي بريد قبل الضغط (مرّر الفأرة فوقه).\n7. لا تستخدم شبكات Wi-Fi العامة بدون VPN.\n\n## علامات الإصابة\n- بطء غير مبرّر في الجهاز.\n- إعلانات ونوافذ منبثقة غريبة.\n- استهلاك إنترنت أعلى من المعتاد.\n- محاولات دخول من أماكن غير مألوفة على بريدك.\n\n## ماذا تفعل عند الاختراق؟\nافصل الإنترنت فوراً، غيّر كلمات السر من جهاز نظيف، أبلغ البنك إذا كانت بياناتك المالية مهددة، واطلب مساعدة متخصّص.'
    WHEN content LIKE '%الشبكات%' OR content LIKE '%شبكات%' THEN
      E'## شبكات الحاسب — العمود الفقري للإنترنت\nكل صورة تُرسلها، كل مكالمة فيديو، كل بحث على جوجل، يمرّ عبر شبكات معقّدة. فهمها يجعلك مستخدماً أذكى وأكثر أماناً.\n\n## مفاهيم أساسية\n- عنوان IP: هويتك على الإنترنت.\n- DNS: دليل الهاتف الذي يحوّل أسماء المواقع إلى أرقام.\n- البروتوكولات: HTTP/HTTPS، TCP/UDP، FTP.\n- الراوتر والسويتش والمودم وأدوار كل منهم.\n- الشبكات اللاسلكية Wi-Fi واختياراتها (5GHz / 2.4GHz).\n\n## كيف تحمي شبكتك المنزلية؟\n1. غيّر كلمة سر الراوتر الافتراضية فوراً.\n2. فعّل تشفير WPA3 أو WPA2 على الأقل.\n3. أوقف WPS لأنه ثغرة شهيرة.\n4. حدّث الـ Firmware للراوتر دورياً.\n5. أنشئ شبكة ضيوف منفصلة لمن يزورك.\n\n## مهارات تفتح أبواب الوظائف\n- شهادة CCNA من سيسكو نقطة انطلاق قوية.\n- تعلّم Linux Networking.\n- إتقان أدوات مثل Wireshark وNmap.\n- فهم الشبكات السحابية AWS / Azure.\n\n## استكشاف الأعطال السريع\n- ping لاختبار الاتصال.\n- traceroute لمعرفة مسار الحزم.\n- إعادة تشغيل الراوتر تحلّ 70% من المشاكل.\n- تأكد من كابلات الإيثرنت فهي أكثر استقراراً من الواي فاي.'
    ELSE E'## محتوى توعوي إضافي\nنواصل في صوت البلد تقديم محتوى توعوي مبسّط يخدم القارئ العربي ويواكب أحدث المستجدات التقنية والمجتمعية.'
  END
  || E'\n\n— — —\n\nبرئاسة د/ محمد الحاجري · تصميم الطالب التقني / خالد عاطف عبد الحكيم'
WHERE category_id = '0654f763-a120-4133-85f2-8b68b7ecdcd7'
  AND content NOT LIKE '%برئاسة د/ محمد الحاجري · تصميم الطالب التقني / خالد عاطف عبد الحكيم';
